"""Android端Python引擎 - 多ASR引擎 + 文本对比
   ASR引擎：Sherpa-ONNX(Java侧) / 百度(内置) / Groq Whisper / OpenAI Whisper / FunASR(局域网)
"""
import os, re, json, base64
from difflib import SequenceMatcher
from functools import lru_cache
try:
    import requests
except ImportError:
    requests = None


# ===== 文档解析 =====
def parse_docx(filepath):
    ext = os.path.splitext(filepath)[1].lower()
    if ext == '.txt':
        with open(filepath, 'r', encoding='utf-8') as f:
            return [l.strip() for l in f if l.strip()]
    import zipfile
    from xml.etree import ElementTree
    ns = '{http://schemas.openxmlformats.org/wordprocessingml/2006/main}'
    paragraphs = []
    with zipfile.ZipFile(filepath) as z:
        with z.open('word/document.xml') as f:
            tree = ElementTree.parse(f)
    for p in tree.iter(f'{ns}p'):
        texts = [t.text for t in p.iter(f'{ns}t') if t.text]
        line = ''.join(texts).strip()
        if line:
            paragraphs.append(line)
    return paragraphs


# ===== 文本规范化 =====
_RE_PUNCT = re.compile(r'[，。！？；：、\u201c\u201d\u2018\u2019（）【】《》…—·\s,.!?;:\'\"()\[\]{}\-]')
FILLER_WORDS = {'嗯', '呃', '啊', '哦', '呢', '吧', '嘛', '哈', '噢', '诶',
                '那个', '就是', '然后', '就是说', '对吧', '对的', '这个'}
CN_NUM = {'0':'零','1':'一','2':'二','3':'三','4':'四','5':'五','6':'六','7':'七','8':'八','9':'九'}
_RE_SENT_SPLIT = re.compile(r'(?<=[。！？；\n])\s*')

def _norm(text):
    return _RE_PUNCT.sub('', text)

def _segment(text):
    return [c for c in text if c.strip()]

def _num_reading(text):
    result = re.sub(r'(\d{4})年', lambda m: ''.join(CN_NUM.get(d,d) for d in m.group(1))+'年', text)
    result = re.sub(r'(\d+)%', lambda m: '百分之'+''.join(CN_NUM.get(d,d) for d in m.group(1)), result)
    return re.sub(r'(\d+)', lambda m: ''.join(CN_NUM.get(d,d) for d in m.group(1)), result)

def _strip_fillers(text):
    """token级停用词过滤：从文本中移除所有填充词"""
    result = text
    for fw in sorted(FILLER_WORDS, key=len, reverse=True):
        result = result.replace(fw, '')
    return result

@lru_cache(maxsize=2048)
def _get_pinyin(text):
    """缓存拼音转换结果"""
    try:
        from pypinyin import pinyin, Style
        return tuple(tuple(p) for p in pinyin(text, style=Style.TONE3, neutral_tone_with_five=True))
    except ImportError:
        return None

def _same_pinyin(a, b):
    """读音比较（带LRU缓存）：字数相同且读音一致视为合格
    支持中文同音字、数字读音、英语大小写
    """
    a_c, b_c = _norm(a), _norm(b)
    if not a_c or not b_c:
        return False
    if a_c == b_c:
        return True
    if a_c.lower() == b_c.lower():
        return True
    a_n, b_n = _num_reading(a_c), _num_reading(b_c)
    if a_n == b_n:
        return True
    # 缓存拼音比较
    pa = _get_pinyin(a_c)
    pb = _get_pinyin(b_c)
    if pa is not None and pb is not None:
        if pa == pb:
            return True
        pa_n = _get_pinyin(a_n)
        pb_n = _get_pinyin(b_n)
        if pa_n is not None and pb_n is not None and pa_n == pb_n:
            return True
    return False


# ===== 对比算法（分层对齐 + 加权CER） =====
def _align_chars(doc_chars, audio_chars, max_window=500):
    """字级对齐：对两段文本做 SequenceMatcher，返回差异列表
    max_window: 超过此长度分段处理避免 O(n*m) 爆炸
    """
    if len(doc_chars) + len(audio_chars) <= max_window:
        return _get_char_diffs(doc_chars, audio_chars)

    # 分段处理：按 max_window/2 窗口滑动
    half = max_window // 2
    all_diffs = []
    di = ai = 0
    while di < len(doc_chars) or ai < len(audio_chars):
        d_end = min(di + half, len(doc_chars))
        a_end = min(ai + half, len(audio_chars))
        chunk_diffs = _get_char_diffs(doc_chars[di:d_end], audio_chars[ai:a_end])
        for d in chunk_diffs:
            d['_doc_offset'] = di
            d['_audio_offset'] = ai
        all_diffs.extend(chunk_diffs)
        di = d_end
        ai = a_end
    return all_diffs


def _get_char_diffs(doc_chars, audio_chars):
    """单窗口内的字级差异提取"""
    matcher = SequenceMatcher(None, doc_chars, audio_chars)
    diffs = []
    for tag, i1, i2, j1, j2 in matcher.get_opcodes():
        if tag == 'equal':
            continue
        doc_frag = ''.join(doc_chars[i1:i2])
        audio_frag = ''.join(audio_chars[j1:j2])
        diffs.append({
            'tag': tag, 'doc_frag': doc_frag, 'audio_frag': audio_frag,
            'di1': i1, 'di2': i2, 'ai1': j1, 'ai2': j2
        })
    return diffs


def compare_texts(audio_text, doc_text):
    """分层对比：句切分 → 句级对齐 → 句内字级精修
    返回: (summary, diffs_list)
    """
    # 句切分
    doc_sents = [s for s in _RE_SENT_SPLIT.split(doc_text) if s.strip()]
    audio_sents = [s for s in _RE_SENT_SPLIT.split(audio_text) if s.strip()]

    # 如果句太少（或没标点），退化为整段对比
    if len(doc_sents) <= 1 and len(audio_sents) <= 1:
        return _compare_flat(audio_text, doc_text)

    # 句级对齐
    doc_sent_norms = [_norm(s) for s in doc_sents]
    audio_sent_norms = [_norm(s) for s in audio_sents]
    sent_matcher = SequenceMatcher(None, doc_sent_norms, audio_sent_norms)

    all_diffs = []
    sub_chars = del_chars = ins_chars = 0

    for tag, i1, i2, j1, j2 in sent_matcher.get_opcodes():
        if tag == 'equal':
            continue

        # 对不一致的句组，做字级精修
        doc_block = ''.join(doc_sents[i1:i2])
        audio_block = ''.join(audio_sents[j1:j2])
        d_chars = _segment(_norm(doc_block))
        a_chars = _segment(_norm(audio_block))

        char_diffs = _align_chars(d_chars, a_chars)
        for cd in char_diffs:
            d_frag = cd['doc_frag']
            a_frag = cd['audio_frag']
            ct = cd['tag']

            # token级填充词过滤
            if ct == 'insert':
                cleaned = _strip_fillers(a_frag)
                if not cleaned.strip():
                    continue
            if ct == 'delete':
                cleaned = _strip_fillers(d_frag)
                if not cleaned.strip():
                    continue
            if ct == 'replace':
                d_clean = _strip_fillers(d_frag)
                a_clean = _strip_fillers(a_frag)
                if not d_clean.strip() and not a_clean.strip():
                    continue
                if _same_pinyin(d_frag, a_frag):
                    continue
            if not d_frag.strip() and not a_frag.strip():
                continue

            dtype = '误读' if ct == 'replace' else ('漏读' if ct == 'delete' else '多读')
            if ct == 'replace':
                all_diffs.append('[%s] 原文: %s → 录音: %s' % (dtype, d_frag, a_frag))
                sub_chars += max(len(d_frag), len(a_frag))
            elif ct == 'delete':
                all_diffs.append('[%s] %s' % (dtype, d_frag))
                del_chars += len(d_frag)
            else:
                all_diffs.append('[%s] %s' % (dtype, a_frag))
                ins_chars += len(a_frag)

    n_mis = sum(1 for d in all_diffs if d.startswith('[误读'))
    n_miss = sum(1 for d in all_diffs if d.startswith('[漏读'))
    n_extra = sum(1 for d in all_diffs if d.startswith('[多读'))

    # 加权 CER：substitution 1.0, deletion 1.0, insertion 0.5
    total = max(len(_norm(doc_text)), 1)
    weighted_errors = sub_chars * 1.0 + del_chars * 1.0 + ins_chars * 0.5
    accuracy = max(0, (1 - weighted_errors / total) * 100)
    cer = min(100, weighted_errors / total * 100)

    summary = '共%d处差异：%d处误读，%d处漏读，%d处多读\n字准确率 %.1f%% (CER %.1f%%)' % (
        len(all_diffs), n_mis, n_miss, n_extra, accuracy, cer)
    return summary, all_diffs


def _compare_flat(audio_text, doc_text):
    """退化的整段字级对比（无句切分时使用）"""
    audio_norm = _norm(audio_text)
    doc_norm = _norm(doc_text)
    audio_words = _segment(audio_norm)
    doc_words = _segment(doc_norm)

    char_diffs = _align_chars(doc_words, audio_words)
    diffs = []
    sub_chars = del_chars = ins_chars = 0

    for cd in char_diffs:
        d_frag = cd['doc_frag']
        a_frag = cd['audio_frag']
        ct = cd['tag']

        if ct == 'insert':
            cleaned = _strip_fillers(a_frag)
            if not cleaned.strip():
                continue
        if ct == 'delete':
            cleaned = _strip_fillers(d_frag)
            if not cleaned.strip():
                continue
        if ct == 'replace':
            if _same_pinyin(d_frag, a_frag):
                continue
        if not d_frag.strip() and not a_frag.strip():
            continue

        dtype = '误读' if ct == 'replace' else ('漏读' if ct == 'delete' else '多读')
        if ct == 'replace':
            diffs.append('[%s] 原文: %s → 录音: %s' % (dtype, d_frag, a_frag))
            sub_chars += max(len(d_frag), len(a_frag))
        elif ct == 'delete':
            diffs.append('[%s] %s' % (dtype, d_frag))
            del_chars += len(d_frag)
        else:
            diffs.append('[%s] %s' % (dtype, a_frag))
            ins_chars += len(a_frag)

    n_mis = sum(1 for d in diffs if d.startswith('[误读'))
    n_miss = sum(1 for d in diffs if d.startswith('[漏读'))
    n_extra = sum(1 for d in diffs if d.startswith('[多读'))
    total = max(len(doc_norm), 1)
    weighted_errors = sub_chars * 1.0 + del_chars * 1.0 + ins_chars * 0.5
    accuracy = max(0, (1 - weighted_errors / total) * 100)
    cer = min(100, weighted_errors / total * 100)

    summary = '共%d处差异：%d处误读，%d处漏读，%d处多读\n字准确率 %.1f%% (CER %.1f%%)' % (
        len(diffs), n_mis, n_miss, n_extra, accuracy, cer)
    return summary, diffs


# ===== 百度语音识别（内置密钥） =====
BAIDU_KEY = 'WRNGMiXLtsPvIAeh9pFhnM2W'
BAIDU_SECRET = 'e6nlIRVT25qSuABjRmx21kRoHha2w4t4'

def transcribe_baidu(filepath):
    """百度语音识别 - 自动分段突破60秒限制"""
    resp = requests.post('https://aip.baidubce.com/oauth/2.0/token',
        params={'grant_type': 'client_credentials',
                'client_id': BAIDU_KEY, 'client_secret': BAIDU_SECRET}, timeout=10)
    token = resp.json().get('access_token', '')
    if not token:
        raise Exception('百度Token获取失败')

    with open(filepath, 'rb') as f:
        audio_data = f.read()

    # 自动分段：超过1.5MB就分段（约50秒@16kHz）
    if len(audio_data) > 1500000:
        return _transcribe_baidu_chunked(filepath, token)

    result = requests.post('https://vop.baidu.com/server_api', json={
        'format': 'wav', 'rate': 16000, 'channel': 1,
        'cuid': 'voicedoc_apk', 'token': token,
        'speech': base64.b64encode(audio_data).decode(),
        'len': len(audio_data), 'dev_pid': 1537
    }, timeout=60).json()

    if result.get('err_no', -1) == 0:
        return ''.join(result.get('result', []))
    raise Exception('百度识别失败[%s]: %s' % (result.get('err_no', '?'), result.get('err_msg', '未知错误')))


def _transcribe_baidu_chunked(filepath, token):
    """百度语音分段转写"""
    import tempfile, subprocess
    tmpdir = tempfile.mkdtemp()
    chunk_pattern = os.path.join(tmpdir, 'chunk_%03d.wav')

    try:
        subprocess.run([
            'ffmpeg', '-i', filepath, '-f', 'segment', '-segment_time', '50',
            '-ac', '1', '-ar', '16000', '-acodec', 'pcm_s16le', '-y', chunk_pattern
        ], capture_output=True, timeout=120)
    except:
        # 没有ffmpeg就用Python切分
        chunks = _split_wav_simple(filepath, tmpdir, 50)
    else:
        chunks = sorted([os.path.join(tmpdir, f) for f in os.listdir(tmpdir) if f.startswith('chunk_')])

    if not chunks:
        raise Exception('音频分段失败')

    results = []
    for chunk in chunks:
        with open(chunk, 'rb') as f:
            data = f.read()
        if len(data) < 100:
            continue
        try:
            r = requests.post('https://vop.baidu.com/server_api', json={
                'format': 'wav', 'rate': 16000, 'channel': 1,
                'cuid': 'voicedoc_apk', 'token': token,
                'speech': base64.b64encode(data).decode(),
                'len': len(data), 'dev_pid': 1537
            }, timeout=60).json()
            if r.get('err_no', -1) == 0:
                text = ''.join(r.get('result', []))
                if text.strip():
                    results.append(text)
        except:
            pass
        try:
            os.remove(chunk)
        except:
            pass
    try:
        os.rmdir(tmpdir)
    except:
        pass
    return ''.join(results) if results else '分段识别全部失败'


def _split_wav_simple(filepath, output_dir, segment_sec):
    """简易WAV切分"""
    try:
        import wave
        with wave.open(filepath, 'rb') as wf:
            params = wf.getparams()
            framerate = wf.getframerate()
            frames_per_chunk = int(framerate * segment_sec)
            total = wf.getnframes()
            chunks = []
            i = 0
            while wf.tell() < total:
                data = wf.readframes(frames_per_chunk)
                if len(data) < framerate:  # 不足1秒
                    break
                path = os.path.join(output_dir, 'chunk_%03d.wav' % i)
                with wave.open(path, 'wb') as out:
                    out.setparams(params)
                    out.writeframes(data)
                chunks.append(path)
                i += 1
            return chunks
    except:
        return []


# ===== Groq Whisper =====
GROQ_BUILTIN_KEY = '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'

def transcribe_groq(filepath, api_key=''):
    """Groq Whisper API - 内置密钥，无需用户配置"""
    if not api_key:
        api_key = GROQ_BUILTIN_KEY

    with open(filepath, 'rb') as f:
        resp = requests.post('https://api.groq.com/openai/v1/audio/transcriptions',
            headers={'Authorization': 'Bearer %s' % api_key},
            files={'file': (os.path.basename(filepath), f, 'audio/wav')},
            data={'model': 'whisper-large-v3', 'language': 'zh',
                  'response_format': 'text'},
            timeout=180)

    if resp.status_code != 200:
        raise Exception('Groq API错误 HTTP %d: %s' % (resp.status_code, resp.text[:200]))

    result = resp.text
    if not result or result.startswith('{"error"'):
        raise Exception('Groq识别失败: %s' % result[:200])

    return result


# ===== FunASR 局域网 =====
def transcribe_funasr(filepath, server_url):
    """FunASR局域网服务"""
    try:
        r = requests.get('%s/health' % server_url, timeout=3)
        if r.status_code != 200:
            raise Exception('FunASR服务未响应')
    except requests.exceptions.ConnectionError:
        raise Exception('无法连接FunASR服务(%s)\n请确认手机和电脑在同一WiFi' % server_url)

    with open(filepath, 'rb') as f:
        resp = requests.post('%s/transcribe_file' % server_url,
            files={'file': (os.path.basename(filepath), f)}, timeout=600)

    if resp.status_code == 404:
        resp = requests.post('%s/transcribe' % server_url,
            json={'file_path': os.path.abspath(filepath)}, timeout=600)

    data = resp.json()
    if not data.get('success'):
        raise Exception(data.get('error', 'FunASR转写失败'))
    return data.get('text', '')


# ===== OpenAI Whisper =====
def transcribe_openai(filepath, api_key=''):
    """OpenAI Whisper API"""
    if not api_key:
        raise Exception('请先在设置中配置OpenAI API Key')

    with open(filepath, 'rb') as f:
        resp = requests.post('https://api.openai.com/v1/audio/transcriptions',
            headers={'Authorization': 'Bearer %s' % api_key},
            files={'file': (os.path.basename(filepath), f, 'audio/wav')},
            data={'model': 'whisper-1', 'response_format': 'text'},
            timeout=120)

    if resp.status_code != 200:
        raise Exception('OpenAI API错误 HTTP %d: %s' % (resp.status_code, resp.text[:200]))

    result = resp.text
    if not result or result.startswith('{"error'):
        raise Exception('OpenAI识别失败: %s' % result[:200])

    return result


# ===== 统一转录入口（Python侧，非Sherpa） =====
def transcribe(filepath, provider, extra_arg=''):
    """Python端ASR转录（百度/Groq/FunASR/OpenAI）"""
    if provider == 'baidu_builtin':
        return transcribe_baidu(filepath)
    elif provider == 'groq_whisper':
        return transcribe_groq(filepath, extra_arg or GROQ_BUILTIN_KEY)
    elif provider == 'funasr':
        return transcribe_funasr(filepath, extra_arg or 'http://192.168.1.100:8765')
    elif provider == 'openai_whisper':
        return transcribe_openai(filepath, extra_arg)
    else:
        raise Exception('不支持的ASR引擎: %s' % provider)


# ===== 测试ASR连通性 =====
def test_asr(provider, extra_arg=''):
    """测试ASR引擎连通性"""
    try:
        if provider == 'baidu_builtin':
            resp = requests.post('https://aip.baidubce.com/oauth/2.0/token',
                params={'grant_type': 'client_credentials',
                        'client_id': BAIDU_KEY, 'client_secret': BAIDU_SECRET}, timeout=5)
            token = resp.json().get('access_token', '')
            if token:
                return '百度语音: 连接成功，Token已获取'
            return '百度语音: Token获取失败'

        elif provider == 'groq_whisper':
            key = extra_arg if extra_arg else GROQ_BUILTIN_KEY
            resp = requests.get('https://api.groq.com/openai/v1/models',
                headers={'Authorization': 'Bearer %s' % key}, timeout=5)
            if resp.status_code == 200:
                return 'Groq Whisper: API Key有效'
            return 'Groq Whisper: API Key无效 (HTTP %d)' % resp.status_code

        elif provider == 'funasr':
            url = extra_arg or 'http://192.168.1.100:8765'
            resp = requests.get('%s/health' % url, timeout=3)
            if resp.status_code == 200:
                return 'FunASR: 服务连接成功'
            return 'FunASR: 服务未响应'

        elif provider == 'openai_whisper':
            key = extra_arg if extra_arg else ''
            if not key:
                return 'OpenAI Whisper: 请先在设置中配置API Key'
            resp = requests.get('https://api.openai.com/v1/models',
                headers={'Authorization': 'Bearer %s' % key}, timeout=5)
            if resp.status_code == 200:
                return 'OpenAI Whisper: API Key有效'
            return 'OpenAI Whisper: API Key无效 (HTTP %d)' % resp.status_code

        elif provider == 'sherpa_offline':
            return 'Sherpa-ONNX: 离线模型，无需网络连接'
        else:
            return '未知引擎: %s' % provider
    except Exception as e:
        return '测试失败: %s' % str(e)


