    data = resp.json()
    text = data.get('text', '')
    timestamps = []
    if 'words' in data:
        for w in data['words']:
            timestamps.append({
                'word': w.get('word', ''),
                'start': w.get('start', 0),
                'end': w.get('end', 0)
            })

    return text, timestamps


