def transcribe(filepath, provider, extra_arg=''):
    """Python端ASR转录，返回文本（兼容旧接口）"""
    result = transcribe_with_ts(filepath, provider, extra_arg)
    return result['text']


def transcribe_with_ts(filepath, provider, extra_arg=''):
    """Python端ASR转录，返回 {'text': ..., 'timestamps': [...]}"""
    if provider == 'baidu_builtin':
        text = transcribe_baidu(filepath)
        # 百度不返回时间戳，生成近似时间戳
        duration = _get_audio_duration_python(filepath)
        timestamps = create_approx_timestamps(text, duration)
        return {'text': text, 'timestamps': timestamps}
    elif provider == 'groq_whisper':
        text, timestamps = transcribe_groq(filepath, extra_arg or GROQ_BUILTIN_KEY)
        return {'text': text, 'timestamps': timestamps}
    elif provider == 'funasr':
        text, timestamps = transcribe_funasr(filepath, extra_arg or 'http://192.168.1.100:8765')
        return {'text': text, 'timestamps': timestamps}
    elif provider == 'openai_whisper':
        text, timestamps = transcribe_openai(filepath, extra_arg)
        return {'text': text, 'timestamps': timestamps}
    else:
        raise Exception('不支持的ASR引擎: %s' % provider)


def _get_audio_duration_python(filepath):
    """获取音频时长（秒）"""
    try:
        import wave
        with wave.open(filepath, 'rb') as wf:
            return wf.getnframes() / wf.getframerate()
    except:
        try:
            return os.path.getsize(filepath) / 32000.0
        except:
            return 60.0


def create_approx_timestamps(text, duration_sec):
    """根据文本长度和音频时长，生成近似的逐字时间戳（精确到秒）
    用于没有精确时间戳的ASR引擎（如百度、Sherpa离线）
    """
    clean = re.sub(r'\s+', '', text)
    if not clean or duration_sec <= 0:
        return []
    char_dur = duration_sec / len(clean)
    timestamps = []
    t = 0.0
    for ch in clean:
        timestamps.append({
            'word': ch,
            'start': round(t, 2),
            'end': round(t + char_dur, 2)
        })
        t += char_dur
    return timestamps


# ===== LLM智能审核差异 =====
def llm_review_diffs(diffs, doc_text, audio_text, llm_provider, llm_key):
    """用大模型审核差异列表，过滤掉转写误差（同音字/近音字），只保留真正的配音错误
    返回过滤后的差异列表
    """
    if not llm_key or not llm_provider or not diffs:
        return diffs

    ep_info = LLM_ENDPOINTS.get(llm_provider)
    if not ep_info:
        return diffs

    endpoint = ep_info['endpoint']
    model = LLM_MODELS.get(llm_provider, 'model')

    # 构建差异摘要供LLM审核
    diff_lines = []
    for i, d in enumerate(diffs):
        dtype = d.get('type', '')
        doc_t = d.get('docText', '')
        audio_t = d.get('audioText', '')
        if dtype == 'mismatch':
            diff_lines.append('%d. 原文「%s」→ 录音「%s」' % (i, doc_t, audio_t))
        elif dtype in ('missing', 'missing_in_audio'):
            diff_lines.append('%d. 漏读「%s」' % (i, doc_t))
        elif dtype in ('extra', 'extra_in_audio'):
            diff_lines.append('%d. 多读「%s」' % (i, audio_t))

    if not diff_lines:
        return diffs

    # 分批审核（每批最多30条，避免token超限）
    batch_size = 30
    all_keep = set(range(len(diffs)))

    for batch_start in range(0, len(diff_lines), batch_size):
        batch = diff_lines[batch_start:batch_start + batch_size]
        prompt = (
            '你是配音质量检查专家。以下是语音转写与原文档的差异列表。\n'
            '这是配音质量核对，不是文字核对。判断标准：\n'
            '1. 只要发音（拼音+声调）正确，就算合格，不是差异。例如"上帝"和"尚地"发音相同，合格。\n'
            '2. 同音字、近音字属于转写引擎误差，不是配音错误，应标记为合格。\n'
            '3. 语气词差异（嗯、啊、哦等）不算错误。\n'
            '4. 只有真正读错发音、漏读、多读才是差异。\n\n'
            '差异列表：\n%s\n\n'
            '请逐条判断，只输出需要删除（合格/不是真正差异）的编号，用逗号分隔。\n'
            '如果全部都是真正差异，输出"无"。只输出编号，不要解释。'
        ) % '\n'.join(batch)

        try:
            if llm_provider == 'claude':
                headers = {
                    'x-api-key': llm_key,
                    'anthropic-version': '2023-06-01',
                    'Content-Type': 'application/json',
                }
                data = {
                    'model': model, 'max_tokens': 200,
                    'messages': [{'role': 'user', 'content': prompt}],
                }
            elif llm_provider == 'zhipu':
                headers = {
                    'Authorization': 'Bearer %s' % llm_key,
                    'Content-Type': 'application/json',
                }
                data = {
                    'model': model, 'max_tokens': 200, 'stream': False,
                    'messages': [{'role': 'user', 'content': prompt}],
                }
            else:
                headers = {
                    'Authorization': 'Bearer %s' % llm_key,
                    'Content-Type': 'application/json',
                }
                data = {
                    'model': model, 'max_tokens': 200,
                    'messages': [{'role': 'user', 'content': prompt}],
                }

            resp = requests.post(endpoint, headers=headers, json=data, timeout=30)
            if resp.status_code in (200, 201):
                resp_data = resp.json()
                if llm_provider == 'claude':
                    content = resp_data.get('content', [{}])[0].get('text', '')
                else:
                    content = resp_data.get('choices', [{}])[0].get('message', {}).get('content', '')

                # 解析LLM返回的编号
                if content and content.strip() != '无':
                    nums = re.findall(r'\d+', content)
                    for n in nums:
                        idx = int(n)
                        if 0 <= idx < len(diffs):
                            all_keep.discard(idx)
        except Exception as e:
            print('LLM审核异常: %s' % e)

    # 返回过滤后的差异
    return [diffs[i] for i in sorted(all_keep)]


