            data = {
                'model': model,
                'messages': [{'role': 'user', 'content': 'hi'}],
                'max_tokens': 10,
                'stream': False,
            }
        else:
            headers = {
                'Authorization': 'Bearer %s' % api_key,
                'Content-Type': 'application/json',
            }
            data = {
                'model': model,
                'max_tokens': 10,
                'messages': [{'role': 'user', 'content': 'hi'}],
