335→    // ===== 音频解码：支持所有格式(WAV/MP3/M4A/FLAC/AMR/OGG...) =====
336→    private float[] decodeAudio(String filepath) throws Exception {
337→        MediaExtractor extractor = new MediaExtractor();
338→        extractor.setDataSource(filepath);
339→
340→        // 查找音频轨道
341→        int trackIndex = -1;
342→        MediaFormat format = null;
343→        for (int i = 0; i < extractor.getTrackCount(); i++) {
344→            MediaFormat f = extractor.getTrackFormat(i);
345→            String mime = f.getString(MediaFormat.KEY_MIME);
346→            if (mime != null && mime.startsWith("audio/")) {
347→                trackIndex = i;
348→                format = f;
349→                break;
350→            }
351→        }
352→        if (trackIndex < 0) {
353→            throw new Exception("未找到音频轨道，文件可能不是音频格式");
354→        }
355→
356→        extractor.selectTrack(trackIndex);
357→        String mime = format.getString(MediaFormat.KEY_MIME);
358→        int sampleRate = format.getInteger(MediaFormat.KEY_SAMPLE_RATE);
359→        int channels = format.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
360→        Log.i(TAG, "音频格式: " + mime + ", " + sampleRate + "Hz, " + channels + "ch");
361→
362→        ByteArrayOutputStream pcmOut = new ByteArrayOutputStream();
363→
364→        if ("audio/raw".equals(mime)) {
365→            // PCM WAV: 直接从extractor读取，不需要codec解码
366→            ByteBuffer buf = ByteBuffer.allocate(65536);
367→            while (extractor.readSampleData(buf, 0) >= 0) {
368→                int pos = buf.position();
369→                byte[] chunk = new byte[pos];
370→                buf.flip();
371→                buf.get(chunk);
372→                pcmOut.write(chunk);
373→                buf.clear();
374→                extractor.advance();
375→            }
376→        } else {
377→            // 压缩格式(MP3/AAC/FLAC/AMR等): 用MediaCodec解码
378→            MediaCodec codec = MediaCodec.createDecoderByType(mime);
379→            codec.configure(format, null, null, 0);
380→            codec.start();
381→
382→            MediaCodec.BufferInfo info = new MediaCodec.BufferInfo();
383→            boolean inputDone = false;
384→            boolean outputDone = false;
385→
386→            while (!outputDone) {
387→                // 送入压缩数据
388→                if (!inputDone) {
389→                    int inputIdx = codec.dequeueInputBuffer(10000);
390→                    if (inputIdx >= 0) {
391→                        ByteBuffer inputBuf = codec.getInputBuffer(inputIdx);
392→                        int size = extractor.readSampleData(inputBuf, 0);
393→                        if (size < 0) {
394→                            codec.queueInputBuffer(inputIdx, 0, 0, 0,
395→                                MediaCodec.BUFFER_FLAG_END_OF_STREAM);
396→                            inputDone = true;
397→                        } else {
398→                            codec.queueInputBuffer(inputIdx, 0, size,
399→                                extractor.getSampleTime(), 0);
400→                            extractor.advance();
401→                        }
402→                    }
403→                }
404→
405→                // 取出PCM数据
406→                int outputIdx = codec.dequeueOutputBuffer(info, 10000);
407→                if (outputIdx >= 0) {
408→                    if ((info.flags & MediaCodec.BUFFER_FLAG_END_OF_STREAM) != 0) {
409→                        outputDone = true;
410→                    }
411→                    if (info.size > 0) {
412→                        ByteBuffer outputBuf = codec.getOutputBuffer(outputIdx);
413→                        byte[] chunk = new byte[info.size];
414→                        outputBuf.get(chunk);
415→                        pcmOut.write(chunk);
416→                    }
417→                    codec.releaseOutputBuffer(outputIdx, false);
418→                } else if (outputIdx == MediaCodec.INFO_OUTPUT_FORMAT_CHANGED) {
419→                    MediaFormat outFmt = codec.getOutputFormat();
420→                    sampleRate = outFmt.getInteger(MediaFormat.KEY_SAMPLE_RATE);
421→                    channels = outFmt.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
422→                    Log.i(TAG, "解码输出格式: " + sampleRate + "Hz, " + channels + "ch");
423→                }
424→            }
425→
426→            codec.stop();
427→            codec.release();
428→        }
429→
430→        extractor.release();
431→
432→        byte[] pcmBytes = pcmOut.toByteArray();
433→        if (pcmBytes.length < 100) {
434→            throw new Exception("音频解码后数据为空 (原格式: " + mime + ")");
435→        }
436→
437→        // PCM bytes -> float samples (16-bit little-endian)
438→        int numSamples = pcmBytes.length / 2;
439→        float[] allSamples = new float[numSamples];
440→        ByteBuffer bb = ByteBuffer.wrap(pcmBytes).order(ByteOrder.LITTLE_ENDIAN);
441→        for (int i = 0; i < numSamples; i++) {
442→            allSamples[i] = bb.getShort() / 32768.0f;
443→        }
444→
445→        // 立体声 -> 单声道
446→        float[] mono;
447→        if (channels > 1) {
448→            int monoLen = numSamples / channels;
449→            mono = new float[monoLen];
450→            for (int i = 0; i < monoLen; i++) {
451→                float sum = 0;
452→                for (int c = 0; c < channels; c++) {
453→                    sum += allSamples[i * channels + c];
454→                }
455→                mono[i] = sum / channels;
456→            }
457→        } else {
458→            mono = allSamples;
459→        }
460→
461→        // 重采样到16kHz
462→        if (sampleRate != 16000) {
463→            Log.i(TAG, "重采样: " + sampleRate + "Hz -> 16000Hz");
464→            mono = resample(mono, sampleRate, 16000);
465→        }
466→
467→        float durationSec = mono.length / 16000.0f;
468→        Log.i(TAG, "解码完成: " + mono.length + " samples, " +
469→            String.format("%.1f", durationSec) + "s @ 16kHz mono");
470→
471→        if (durationSec < 0.3f) {
472→            throw new Exception("音频太短 (" + String.format("%.1f", durationSec) + "秒)，无法识别");
473→        }
474→
475→        return mono;
476→    }
477→
478→    // ===== 线性插值重采样 =====
479→    private float[] resample(float[] input, int fromRate, int toRate) {
480→        double ratio = (double) fromRate / toRate;
481→        int outputLen = (int) (input.length / ratio);
482→        float[] output = new float[outputLen];
483→        for (int i = 0; i < outputLen; i++) {
484→            double srcIdx = i * ratio;
485→            int idx = (int) srcIdx;
486→            double frac = srcIdx - idx;
487→            if (idx + 1 < input.length) {
488→                output[i] = (float) (input[idx] * (1 - frac) + input[idx + 1] * frac);
489→            } else if (idx < input.length) {
490→                output[i] = input[idx];
491→            }
492→        }
493→        return output;
494→    }
