496→    // ===== Sherpa-ONNX 离线识别（分段提升准确率） =====
497→    private String transcribeSherpa(String audioFile) throws Exception {
498→        // 解码音频为16kHz单声道（支持WAV/MP3/M4A/FLAC/AMR/OGG等）
499→        float[] samples = decodeAudio(audioFile);
500→
501→        AssetManager assetManager = getAssets();
502→
503→        OfflineParaformerModelConfig paraformerConfig = new OfflineParaformerModelConfig();
504→        paraformerConfig.setModel("models/paraformer/model.int8.onnx");
505→
506→        OfflineModelConfig modelConfig = new OfflineModelConfig();
507→        modelConfig.setParaformer(paraformerConfig);
508→        modelConfig.setTokens("models/paraformer/tokens.txt");
509→        modelConfig.setNumThreads(4);
510→        modelConfig.setDebug(false);
511→
512→        OfflineRecognizerConfig config = new OfflineRecognizerConfig();
513→        config.setModelConfig(modelConfig);
514→        config.setDecodingMethod("greedy_search");
515→
516→        OfflineRecognizer recognizer = new OfflineRecognizer(assetManager, config);
517→
518→        // 分段识别：每段30秒，提高长音频准确率
519→        int chunkSamples = 30 * 16000;
520→        int totalChunks = (int) Math.ceil((double) samples.length / chunkSamples);
521→        StringBuilder allText = new StringBuilder();
522→
523→        if (totalChunks <= 1) {
524→            // 短音频直接识别
525→            OfflineStream stream = recognizer.createStream();
526→            stream.acceptWaveform(samples, 16000);
527→            recognizer.decode(stream);
528→            OfflineRecognizerResult result = recognizer.getResult(stream);
529→            allText.append(result.getText() != null ? result.getText().trim() : "");
530→            stream.release();
531→        } else {
532→            // 长音频分段识别
533→            for (int ci = 0; ci < totalChunks; ci++) {
534→                int finalCi = ci;
535→                runOnUiThread(() -> tvStatus.setText(
536→                    String.format("离线识别 %d/%d...", finalCi + 1, totalChunks)));
537→
538→                int start = ci * chunkSamples;
539→                // 加1秒重叠避免截断
540→                int overlap = ci > 0 ? 16000 : 0;
541→                int actualStart = Math.max(0, start - overlap);
542→                int end = Math.min(samples.length, start + chunkSamples);
543→                int len = end - actualStart;
544→
545→                if (len < 1600) continue; // 不足0.1秒跳过
546→
547→                float[] chunk = new float[len];
548→                System.arraycopy(samples, actualStart, chunk, 0, len);
549→
550→                OfflineStream stream = recognizer.createStream();
551→                stream.acceptWaveform(chunk, 16000);
552→                recognizer.decode(stream);
553→                OfflineRecognizerResult result = recognizer.getResult(stream);
554→                String text = result.getText() != null ? result.getText().trim() : "";
555→
556→                if (!text.isEmpty()) {
557→                    // 去除重叠部分导致的重复（最长公共后缀/前缀匹配，窗口30字）
558→                    if (ci > 0 && allText.length() > 0 && overlap > 0) {
559→                        String prev = allText.toString();
560→                        int maxCheck = Math.min(30, Math.min(prev.length(), text.length()));
561→                        int bestMatch = 0;
562→                        for (int t = maxCheck; t > 0; t--) {
563→                            if (prev.endsWith(text.substring(0, t))) {
564→                                bestMatch = t;
565→                                break;
566→                            }
567→                        }
568→                        if (bestMatch > 0) {
569→                            text = text.substring(bestMatch);
570→                        }
571→                    }
572→                    allText.append(text);
573→                }
574→                stream.release();
575→            }
576→        }
577→
578→        recognizer.release();
579→        return allText.toString().trim();
580→    }
