609→                    } else if ("groq_whisper".equals(engineId)) {
610→                        extraArg = prefs.getString("groq_key", GROQ_BUILTIN_KEY);
611→                    } else if ("openai_whisper".equals(engineId)) {
612→                        extraArg = prefs.getString("openai_key", "");
613→                    }
614→
615→                    Python py = Python.getInstance();
616→                    PyObject engine = py.getModule("engine");
617→                    audioText = engine.callAttr("transcribe", audioPath, engineId, extraArg).toString();
618→                }
619→
620→                Log.i(TAG, "ASR结果: " + audioText);
621→
622→                if (audioText.isEmpty()) {
623→                    runOnUiThread(() -> {
624→                        tvStatus.setText("语音识别结果为空，请检查音频是否有语音内容");
625→                        progressBar.setVisibility(View.GONE);
626→                        btnCompare.setEnabled(true);
627→                    });
628→                    return;
629→                }
630→
631→                runOnUiThread(() -> tvStatus.setText("正在对比文本..."));
632→                Python py = Python.getInstance();
633→                PyObject engine = py.getModule("engine");
634→
635→                // 读取文档文本
636→                PyObject paragraphs = engine.callAttr("parse_docx", docPath);
637→                StringBuilder docTextBuilder = new StringBuilder();
638→                for (PyObject p : paragraphs.asList()) {
639→                    if (docTextBuilder.length() > 0) docTextBuilder.append("\n");
640→                    docTextBuilder.append(p.toString());
641→                }
642→                lastDocText = docTextBuilder.toString();
643→
644→                // 使用带时间戳的结构化对比
645→                PyObject result = engine.callAttr("run_compare_with_timestamps",
646→                    audioText, lastDocText, (Object) null);
647→
648→                String summary = result.callAttr("get", "summary").toString();
649→                PyObject diffsObj = result.callAttr("get", "diffs");
650→
651→                // 保存结构化差异JSON（含时间戳）
652→                PyObject jsonMod = py.getModule("json");
653→                lastDiffsJson = jsonMod.callAttr("dumps", diffsObj,
654→                    new com.chaquo.python.Kwarg("ensure_ascii", false)).toString();
655→
656→                // 格式化显示
657→                StringBuilder details = new StringBuilder();
658→                int idx = 1;
659→                for (PyObject d : diffsObj.asList()) {
660→                    String dtype = d.callAttr("get", "type", "").toString();
661→                    String docT = d.callAttr("get", "docText", "").toString();
662→                    String audioT = d.callAttr("get", "audioText", "").toString();
663→                    String typeLabel;
664→                    if ("mismatch".equals(dtype)) {
665→                        typeLabel = "误读";
666→                        details.append(idx).append(". [").append(typeLabel).append("] 原文: ")
667→                            .append(docT).append(" → 录音: ").append(audioT);
668→                    } else if ("missing".equals(dtype)) {
669→                        typeLabel = "漏读";
670→                        details.append(idx).append(". [").append(typeLabel).append("] ").append(docT);
